  function _zonaActualizarPreview() {
    const sub = $('modalZonaSubtitle');
    if (!sub) return;
    const nom = ($('zonaNombre')?.value || '').trim();
    const tg = $('zonaEstadoToggle');
    const activo = tg ? tg.checked : true;
    sub.textContent = nom ? (activo ? '🟢 activa' : '🔴 inactiva') + ' · zona' : 'Punto de venta físico';
  }

  // ¿Es la zona de almacén? Detección heurística por id o nombre.
  // El almacén usa configuración global, no por zona — así que el modal
  // oculta la sección "Política de la zona" para evitar confusión.
  function _esZonaAlmacen(z) {
    if (!z) return false;
    const id = String(z.idZona || '').toUpperCase();
    const nm = String(z.nombre || '').toUpperCase();
    return id === 'ALMACEN' || id === 'ALMACÉN' || nm.indexOf('ALMACEN') >= 0 || nm.indexOf('ALMACÉN') >= 0;
  }

  function abrirModalZona(id) {
    ['Id','Nombre','Direccion','Responsable','Desc','MetaDiaria','ComisionPct','MetaAuditorias'].forEach(f => {
      const el = $('zona' + f); if (el) el.value = '';
    });
    const estadoWrap = $('zonaEstadoWrap');
    const btnElim = $('zonaBtnEliminar');
    const tg = $('zonaEstadoToggle');
    if (id) {
      const z = cfgData.zonas.find(x => x.idZona === id);
      if (!z) return;
      $('modalZonaTitle').textContent = 'Editar Zona';
      $('zonaId').value          = z.idZona;
      $('zonaNombre').value      = z.nombre || '';
      $('zonaDireccion').value   = z.direccion || '';
      $('zonaResponsable').value = z.responsable || '';
      $('zonaEstado').value      = String(z.estado ?? '1');
      $('zonaDesc').value        = z.descripcion || '';
      // Parsear politicaJSON si existe
      try {
        const pol = z.politicaJSON
          ? (typeof z.politicaJSON === 'string' ? JSON.parse(z.politicaJSON) : z.politicaJSON)
          : {};
        if (pol.metaDiaria != null)            $('zonaMetaDiaria').value      = String(pol.metaDiaria);
        if (pol.comisionExcedentePct != null)  $('zonaComisionPct').value     = String(pol.comisionExcedentePct);
        if (pol.metaAuditorias != null)        $('zonaMetaAuditorias').value  = String(pol.metaAuditorias);
      } catch(_){}
      if (tg) tg.checked = String(z.estado) === '1' || z.estado === 1 || z.estado === true;
      if (estadoWrap) estadoWrap.classList.remove('hidden');
      if (btnElim)    btnElim.classList.remove('hidden');
    } else {
      $('modalZonaTitle').textContent = 'Nueva Zona';
      $('zonaId').value = '';
      $('zonaEstado').value = '1';
      if (tg) tg.checked = true;
      if (estadoWrap) estadoWrap.classList.add('hidden');
      if (btnElim)    btnElim.classList.add('hidden');
    }

    // Si es la zona de almacén, ocultar sección "Política de la zona" y
    // mostrar nota — su configuración va en CONFIG_MOS (chips de Operadores).
    const z2 = id ? cfgData.zonas.find(x => x.idZona === id) : null;
    const esAlmacen = _esZonaAlmacen(z2 || { idZona: id });
    const seccionPolitica = document.querySelector('#modalZona .pers-section:has(#zonaMetaDiaria)');
    let notaAlmacen = document.getElementById('zonaNotaAlmacen');
    if (esAlmacen) {
      if (seccionPolitica) seccionPolitica.style.display = 'none';
      if (!notaAlmacen) {
        notaAlmacen = document.createElement('div');
        notaAlmacen.id = 'zonaNotaAlmacen';
        notaAlmacen.className = 'pers-section';
        notaAlmacen.style.cssText = 'border-top:1px dashed #1e293b;padding-top:14px;margin-top:14px';
        notaAlmacen.innerHTML = `
          <div class="pers-section-title" style="display:flex;align-items:center;gap:6px;color:#fbbf24">
            <span>🏭 Zona de almacén</span>
          </div>
          <div class="text-[11px] text-slate-400 p-3 rounded leading-relaxed" style="background:rgba(251,191,36,.05);border:1px dashed rgba(251,191,36,.3)">
            <p>Esta zona es operativa del almacén central. No tiene meta de venta diaria ni comisión porque <b>aquí no se vende</b>.</p>
            <p class="mt-2">La configuración del almacén (tarifa de envasado + meta de auditorías) es <b>global</b> en CONFIG_MOS. Edítala desde:</p>
            <p class="mt-1 text-amber-400 font-bold">Configuración → Personal → sección "Operadores Almacén" (chips arriba a la derecha).</p>
          </div>`;
        const body = document.querySelector('#modalZona .overflow-y-auto');
        if (body) body.appendChild(notaAlmacen);
      } else {
        notaAlmacen.style.display = '';
      }
    } else {
      if (seccionPolitica) seccionPolitica.style.display = '';
      if (notaAlmacen) notaAlmacen.style.display = 'none';
    }

    _zonaActualizarPreview();
    openModal('modalZona');
  }

  async function guardarZona() {
    const nombre = $('zonaNombre')?.value.trim();
    if (!nombre) { toast('Nombre requerido', 'error'); return; }
    const idEdit = $('zonaId')?.value || undefined;
    const tg = $('zonaEstadoToggle');
    const estado = idEdit ? (tg && tg.checked ? '1' : '0') : '1';
    // Construir politicaJSON (meta de venta + % comisión + meta auditorías).
    // Cada campo vacío se omite del JSON (para distinguir "no configurado").
    const metaRaw    = parseFloat($('zonaMetaDiaria')?.value);
    const pctRaw     = parseFloat($('zonaComisionPct')?.value);
    const metaAudRaw = parseFloat($('zonaMetaAuditorias')?.value);
    const politica = {};
    if (!isNaN(metaRaw)    && metaRaw    >= 0)  politica.metaDiaria            = metaRaw;
    if (!isNaN(pctRaw)     && pctRaw     >= 0)  politica.comisionExcedentePct  = pctRaw;
    if (!isNaN(metaAudRaw) && metaAudRaw >= 0)  politica.metaAuditorias        = metaAudRaw;
    const politicaJSON = Object.keys(politica).length ? JSON.stringify(politica) : '';

    const params = {
      idZona:        idEdit,
      nombre,
      descripcion:   $('zonaDesc')?.value || '',
      direccion:     $('zonaDireccion')?.value || '',
      responsable:   $('zonaResponsable')?.value || '',
      estado,
      politicaJSON:  politicaJSON
    };
    if (!params.idZona) delete params.idZona;
    // OPTIMISTA
    const list = cfgData.zonas;
    const backup = list.slice();
    if (idEdit) {
      const idx = list.findIndex(x => x.idZona === idEdit);
      if (idx >= 0) list[idx] = { ...list[idx], ...params };
    } else {
      list.push({ ...params, idZona: 'Z_TMP' + Date.now(), _tmp: true });
    }
    closeModal('modalZona');
    renderInfra();
    try {
      const res = await API.post(idEdit ? 'actualizarZona' : 'crearZona', params);
      if (!idEdit && res?.idZona) {
        const tmp = list.findIndex(x => x._tmp);
        if (tmp >= 0) { list[tmp].idZona = res.idZona; delete list[tmp]._tmp; }
      }
      toast('Zona guardada ✓', 'ok');
      renderInfra();
    } catch(e) {
      cfgData.zonas = backup;
      renderInfra();
      toast('Error: ' + e.message, 'error');
    }
  }

  async function eliminarZona() {
    const id = $('zonaId')?.value;
    if (!id) return;
    const z = cfgData.zonas.find(x => x.idZona === id);
    if (!z) return;
    const numEst = cfgData.estaciones.filter(e => e.idZona === id).length;
    const msg = numEst > 0
      ? `¿Desactivar la zona "${z.nombre}"?\n\nTiene ${numEst} estación${numEst === 1 ? '' : 'es'} asociada${numEst === 1 ? '' : 's'} que dejarán de aparecer en las apps. Puedes reactivarla luego.`
      : `¿Desactivar la zona "${z.nombre}"?\n\nPodrás reactivarla cuando quieras.`;
    if (!confirm(msg)) return;
    closeModal('modalZona');
    // OPTIMISTA: marcar inactiva
    const previo = z.estado;
    z.estado = '0';
    renderInfra();
    try {
      await API.post('actualizarZona', { idZona: id, estado: '0' });
      toast('Zona desactivada', 'ok');
    } catch(e) {
      z.estado = previo;
      renderInfra();
      toast('Error: ' + e.message, 'error');
    }
  }

  // (renderEstaciones() obsoleto — usado renderInfra() para vista jerárquica)

  // (renderImpresoras() obsoleto — usado renderInfra() para vista jerárquica)

  // Helper: actividad del usuario igual que dispositivos
  // Parser defensivo de timestamps Ultima_Conexion / Ultima_Sesion del backend.
  // Caso 1: ISO con Z → JS Date lo parsea correcto.
  // Caso 2: ISO sin Z (legacy "2026-05-09 14:35:29") → SIN este helper JS lo
  //         parseaba como hora LOCAL del browser, dando mismatch de horas vs
  //         server. Aquí lo convertimos manualmente asumiendo UTC.
  // Caso 3: formato US "5/9/2026 9:35:29" → parsear con regex defensivo.
  function _parseTsUtc(raw) {
    if (!raw) return NaN;
    if (raw instanceof Date) return raw.getTime();
    const s = String(raw).trim();
    if (!s) return NaN;
    // ISO con T y Z (o con offset tipo +05:00) — JS lo parsea correctamente
    if (s.indexOf('T') >= 0 && (s.indexOf('Z') >= 0 || /[+-]\d{2}:?\d{2}$/.test(s))) {
      return new Date(s).getTime();
    }
    // ISO sin Z: "2026-05-09 14:35:29" o "2026-05-09T14:35:29" → tratar como UTC
    const isoNoZ = /^(\d{4})-(\d{2})-(\d{2})[T ](\d{1,2}):(\d{2}):(\d{2})/;
    const m1 = s.match(isoNoZ);
    if (m1) {
      return Date.UTC(+m1[1], +m1[2] - 1, +m1[3], +m1[4], +m1[5], +m1[6]);
    }
    // Formato US "5/9/2026 9:35:29" o "05/09/2026 09:35:29" → tratar como UTC
    const usFmt = /^(\d{1,2})\/(\d{1,2})\/(\d{4})\s+(\d{1,2}):(\d{2}):(\d{2})/;
    const m2 = s.match(usFmt);
    if (m2) {
      return Date.UTC(+m2[3], +m2[1] - 1, +m2[2], +m2[4], +m2[5], +m2[6]);
    }
    // Fallback: que JS intente
    const t = new Date(s).getTime();
    return isNaN(t) ? NaN : t;
  }

  function _personaActividad(ultimaConexion) {
    if (!ultimaConexion) return { color: '#64748b', label: 'sin conexión', dot: '⚫', minutos: Infinity };
    const t = _parseTsUtc(ultimaConexion);
    if (isNaN(t)) return { color: '#64748b', label: ultimaConexion, dot: '⚫', minutos: Infinity };
    const min = Math.floor((Date.now() - t) / 60000);
    if (min < 0)       return { color: '#10b981', label: 'online ahora',     dot: '🟢', minutos: 0 }; // server adelantado
    if (min < 5)       return { color: '#10b981', label: 'online ahora',     dot: '🟢', minutos: min };
    if (min < 60)      return { color: '#10b981', label: `hace ${min}m`,     dot: '🟢', minutos: min };
    if (min < 60*24)   return { color: '#fbbf24', label: `hace ${Math.floor(min/60)}h`, dot: '🟡', minutos: min };
    if (min < 60*24*7) return { color: '#f97316', label: `hace ${Math.floor(min/60/24)}d`, dot: '🟠', minutos: min };
    return { color: '#ef4444', label: `inactivo ${Math.floor(min/60/24)}d`, dot: '🔴', minutos: min };
  }

  // Render unificado de card de persona con avatar, indicador online, switch y click
  // Para admins/master: agrega botón 🔑 + sección expandible con auditoría hoy
  function _renderPersonaCard(p, appOrigen) {
    const ini = ((p.nombre || '?')[0] + (p.apellido || '?')[0]).toUpperCase();
    const activo = String(p.estado) === '1';
    const act = _personaActividad(p.Ultima_Conexion || p.ultimaConexion);
    const isFresh = act.minutos < 5;
    const safeId = String(p.idPersonal || '').replace(/'/g, '&#39;');
    const claseFresh = isFresh ? 'disp-chip-live' : '';
    const dotPulse = isFresh ? '<span class="disp-dot-pulse"></span>' : '';
    const opacityCls = (!activo || p._tmp) ? 'opacity-60' : '';
    const glowBg = isFresh ? 'rgba(16,185,129,0.06)' : '#0d1526';
    const glowBorder = isFresh ? 'rgba(16,185,129,0.5)' : '#1e293b';

    const rolUp = String(p.rol || '').toUpperCase();
    const esAdmin = rolUp === 'MASTER' || rolUp === 'ADMIN' || rolUp === 'ADMINISTRADOR';
    const esWH = appOrigen === 'warehouseMos';

    // Última acción para admins (del cache de audit)
    let ultAccion = '';
    if (esAdmin && _personalAuditCache.length) {
      const propias = _personalAuditCache.filter(a => String(a.idPersonalAutoriza) === String(p.idPersonal));
      if (propias.length) {
        const ult = propias[0];
        const f = ult.fecha ? new Date(ult.fecha) : null;
        const fmt = f ? f.toLocaleTimeString('es-PE', { hour: '2-digit', minute: '2-digit' }) : '';
        ultAccion = `<div class="text-[9px] text-indigo-300 mt-1 truncate"><span class="opacity-70">${fmt}</span> · <span class="font-bold uppercase">${ult.accion || '—'}</span>${ult.refDocumento ? ' · ' + ult.refDocumento : ''}</div>`;
      }
    }

    // Botón 🔑 visible solo para admins/master
    const llaveBtn = esAdmin
      ? `<button onclick="event.stopPropagation();MOS.abrirModalClaveGlobal('${safeId}')"
                 class="text-[14px] p-1 rounded hover:bg-amber-500/20 hover:scale-110 transition-all"
                 title="Ver clave global">🔑</button>`
      : '';

    // Botón 💬 SIEMPRE visible (todos pueden recibir push). Círculo azul.
    const safeNombre = String(p.nombre || '').replace(/'/g, '&#39;');
    const pushBtn = `<button onclick="event.stopPropagation();MOS.abrirModalEnviarPush('${safeId}','${safeNombre}')"
                             class="shrink-0 w-8 h-8 rounded-full flex items-center justify-center hover:scale-110 transition-all"
                             style="background:rgba(59,130,246,0.15);border:1px solid rgba(59,130,246,0.5);color:#60a5fa;font-size:13px;"
                             title="Enviar mensaje push a ${p.nombre}">💬</button>`;

    // Botón 📜 Historial JSON — siempre visible (PERSONAL_MASTER.historialCambios)
    const histBtn = `<button onclick="event.stopPropagation();MOS.cfgHistorialPersonal('${safeId}','${safeNombre}')"
                             class="shrink-0 w-8 h-8 rounded-full flex items-center justify-center hover:scale-110 transition-all"
                             style="background:rgba(168,85,247,0.15);border:1px solid rgba(168,85,247,0.5);color:#c084fc;font-size:13px;"
                             title="Ver historial de cambios de ${p.nombre}">📜</button>`;

    // Botón 🕵️ ESPÍA (audio + gps combinados) — siempre visible para no-admins.
    // Si el usuario no está logueado en ningún dispositivo, abrirEspiaPorUsuario muestra toast.
    // Para admins/master se oculta: ellos usan el panel web, no tablets.
    const audioBtn = !esAdmin
      ? `<button onclick="event.stopPropagation();MOS.abrirEspiaPorUsuario('${safeNombre}')"
                 class="shrink-0 w-8 h-8 rounded-full flex items-center justify-center hover:scale-110 transition-all"
                 style="background:rgba(99,102,241,0.18);border:1px solid rgba(99,102,241,0.5);color:#a5b4fc;font-size:13px;"
                 title="Espiar a ${p.nombre} (audio + GPS)">🕵️</button>`
      : '';
    const gpsBtn = '';

    // Audit hoy (solo admins)
    const auditExpand = esAdmin
      ? `<div id="auditDetail_${safeId}" class="hidden mt-2 p-3 rounded-lg" style="background:#0a1424;border:1px solid #1e293b;">
          <div class="text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-2">📋 Acciones de hoy</div>
          <div id="auditList_${safeId}" class="space-y-1 text-[11px] text-slate-400">Cargando...</div>
          <button onclick="event.stopPropagation();MOS.abrirModalHistorialAudit('${safeId}','${(p.nombre || '').replace(/'/g, '&#39;')}')"
            class="mt-2 w-full text-[10px] text-indigo-400 hover:text-white py-1 rounded border border-dashed border-indigo-700/50 hover:border-indigo-500 transition-colors">
            Ver historial completo →
          </button>
        </div>`
      : '';

    return `<div class="pers-card-wrap">
      <div class="disp-chip pers-card-clickable flex items-center gap-3 p-3 rounded-lg cursor-pointer ${claseFresh} ${opacityCls}"
        onclick="${esAdmin ? `MOS._togglePersAudit('${safeId}')` : `MOS.abrirModalPersonal('${safeId}','${appOrigen}')`}"
        style="background:${glowBg};border:1px solid ${glowBorder};transition:all 0.2s;position:relative;"
        title="${esAdmin ? 'Click para ver auditoría' : 'Click para editar'}">
        <div class="relative shrink-0">
          <div class="w-10 h-10 rounded-full flex items-center justify-center text-white text-sm font-bold"
               style="background:${p.color || '#6366f1'}">${ini}</div>
          ${dotPulse}
        </div>
        <div class="flex-1 min-w-0">
          <div class="font-medium text-sm text-slate-200 truncate">${p.nombre} ${p.apellido || ''}</div>
          <div class="flex items-center gap-2 mt-0.5 flex-wrap">
            <span class="badge badge-gray text-[9px] uppercase">${p.rol || '—'}</span>
            ${p.montoBase ? `<span class="text-[9px] text-slate-500">S/.${parseFloat(p.montoBase).toFixed(2)}/día</span>` : ''}
            <span class="text-[9px]" style="color:${act.color};">${act.dot} ${act.label}</span>
          </div>
          ${ultAccion}
        </div>
        ${audioBtn}
        ${gpsBtn}
        ${pushBtn}
        ${histBtn}
        ${llaveBtn}
        <label class="pers-switch shrink-0" title="${activo ? 'Desactivar' : 'Activar'}" onclick="event.stopPropagation()">
          <input type="checkbox" ${activo ? 'checked' : ''} onchange="MOS.togglePersonalActivo('${safeId}','${appOrigen}', event)">
          <span class="pers-switch-slider"></span>
        </label>
        <button onclick="event.stopPropagation();MOS.abrirModalPersonal('${safeId}','${appOrigen}')"
                class="text-[10px] text-slate-500 hover:text-white p-1" title="Editar">✏️</button>
      </div>
      ${auditExpand}
    </div>`;
  }

  // Cache de auditoría (compartido entre cards y modal historial)
  let _personalAuditCache = []; // últimas N entradas
  let _personalIntegCount = 0;
  let _personalNotifCount = 0;

  // Chip de meta editable inline (click → input)
  // Chips bonitos de política dentro de la card de cada zona en Infra.
  // Para zonas POS: meta diaria, comisión %, meta auditorías
  // Para almacén: tarifa envasado, meta guías, meta auditorías (de CONFIG_MOS)
  function _renderChipsPoliticaZona(z) {
    const esAlmacen = _esZonaAlmacen(z);
    let chips = [];

    if (esAlmacen) {
      // Datos del almacén vienen de CONFIG_MOS global
      const cfg = cfgData.config || {};
      const tarifa = cfg.evalTarifaEnvasadoPorUnidad != null ? parseFloat(cfg.evalTarifaEnvasadoPorUnidad) : null;
      const metaGuias = parseFloat(cfg.evalMetaAlmacenero) || 0;
      const metaAud   = parseFloat(cfg.evalMetaAuditorias) || 0;
      if (tarifa != null && !isNaN(tarifa)) {
        chips.push(_chipPolitica('💵', 'Envasado', 'S/ ' + tarifa.toFixed(2), '/und', '#10b981'));
      }
      if (metaGuias > 0) chips.push(_chipPolitica('📦', 'Meta guías', String(metaGuias), '/día', '#ea580c'));
      if (metaAud > 0)   chips.push(_chipPolitica('📋', 'Auditorías', String(metaAud), '/día', '#fbbf24'));
      if (!chips.length) return _chipsAvisoVacio('almacen');
    } else {
      // Política POS desde politicaJSON de la zona
      let pol = {};
      try {
        pol = z.politicaJSON ? (typeof z.politicaJSON === 'string' ? JSON.parse(z.politicaJSON) : z.politicaJSON) : {};
      } catch(_){}
      const meta = parseFloat(pol.metaDiaria);
      const pct  = parseFloat(pol.comisionExcedentePct);
      const aud  = parseFloat(pol.metaAuditorias);
      if (!isNaN(meta) && meta > 0)  chips.push(_chipPolitica('💰', 'Meta venta', 'S/ ' + meta.toFixed(0), '/día', '#f59e0b'));
      if (!isNaN(pct)  && pct  >= 0) chips.push(_chipPolitica('🎯', 'Comisión',   pct + '%',                'excedente', '#10b981'));
      if (!isNaN(aud)  && aud  > 0)  chips.push(_chipPolitica('📋', 'Auditorías', String(aud),              '/día', '#fbbf24'));
      if (!chips.length) return _chipsAvisoVacio('pos', z.idZona);
    }
    return `<div class="flex flex-wrap gap-1.5 mb-3 px-1">${chips.join('')}</div>`;
  }

  function _chipPolitica(icon, label, valor, unidad, color) {
    return `<span class="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-lg text-[11px]"
      style="background:rgba(99,102,241,0.05);border:1px solid ${color}66;color:#e2e8f0">
      <span>${icon}</span>
      <span class="text-slate-400 text-[10px]">${label}</span>
      <span style="color:${color}" class="font-black">${valor}</span>
      <span class="text-slate-500 text-[9px]">${unidad}</span>
    </span>`;
  }

  function _chipsAvisoVacio(tipo, idZona) {
    const mensaje = tipo === 'almacen'
      ? '⚠ Almacén sin tarifa/metas configuradas — edita en Personal → Operadores'
      : '⚠ Sin meta configurada — click ✏️ arriba para llenarla';
    return `<div class="px-3 py-2 mb-3 rounded-lg text-[11px] text-red-300"
      style="background:rgba(248,113,113,0.08);border:1px dashed rgba(248,113,113,0.4)">
      ${mensaje}
    </div>`;
  }

  // ── Render compacto: meta + comisión POR ZONA ─────────────────
  // Reemplaza el chip global confuso. Cada zona se edita aparte abriendo
  // su modal de edición. Si no tiene política configurada → badge ⚠.
  function _renderMetasPorZona() {
    // Excluir zonas de almacén — no tienen política de venta. Sus reglas
    // (tarifa envasado + meta auditorías) viven en CONFIG_MOS global y se
    // editan desde la sección "Operadores Almacén".
    const zonas = (cfgData.zonas || []).filter(z => {
      const activa = String(z.estado) === '1' || z.estado === 1 || z.estado === true;
      return activa && !_esZonaAlmacen(z);
    });
    if (!zonas.length) {
      return `<div class="p-3 mb-3 rounded-lg text-[12px] text-slate-500 italic text-center"
                   style="background:#0a1424;border:1px dashed #334155">
        Sin zonas activas. Crea una zona en
        <a href="javascript:MOS.nav('config');setTimeout(()=>MOS.setCfgTab('infra'),50)"
           class="text-amber-400 hover:underline">Infraestructura</a> para configurar su meta diaria.
      </div>`;
    }
    const rows = zonas.map(z => {
      let pol = {};
      try {
        pol = z.politicaJSON ? (typeof z.politicaJSON === 'string' ? JSON.parse(z.politicaJSON) : z.politicaJSON) : {};
      } catch(_){}
      const meta    = parseFloat(pol.metaDiaria);
      const pct     = parseFloat(pol.comisionExcedentePct);
      const metaAud = parseFloat(pol.metaAuditorias);
      const hasMeta = !isNaN(meta) && meta > 0;
      const hasPct  = !isNaN(pct)  && pct  >= 0;
      const hasAud  = !isNaN(metaAud) && metaAud > 0;
      const completa = hasMeta && hasPct;
      const idAttr = String(z.idZona).replace(/'/g, '&#39;');
      return `<div class="flex items-center gap-2 px-3 py-2 rounded-lg cursor-pointer transition-all hover:scale-[1.01]"
                   onclick="MOS.abrirModalZona('${idAttr}')"
                   style="background:rgba(245,158,11,0.06);border:1px solid ${completa ? 'rgba(245,158,11,0.3)' : 'rgba(248,113,113,0.4)'};">
        <span class="text-base flex-shrink-0">🏬</span>
        <div class="flex-1 min-w-0">
          <div class="text-[12px] font-bold text-amber-100 truncate">${String(z.nombre || z.idZona).replace(/[<>&]/g, c => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c]))}</div>
          <div class="flex flex-wrap items-center gap-x-3 gap-y-0.5 text-[11px] mt-0.5">
            <span class="${hasMeta ? 'text-amber-300' : 'text-red-400'}">
              <span class="opacity-70">Meta:</span>
              <span class="font-bold">${hasMeta ? 'S/ ' + meta.toFixed(0) : 'sin configurar'}</span>
            </span>
            <span class="${hasPct ? 'text-emerald-300' : 'text-red-400'}">
              <span class="opacity-70">Comisión:</span>
              <span class="font-bold">${hasPct ? pct + '%' : 'sin configurar'}</span>
            </span>
            <span class="${hasAud ? 'text-sky-300' : 'text-slate-500'}">
              <span class="opacity-70">Auditorías:</span>
              <span class="font-bold">${hasAud ? metaAud.toFixed(0) + '/día' : 'global'}</span>
            </span>
          </div>
        </div>
        ${completa
          ? '<span class="text-[10px] opacity-50">✏️</span>'
          : '<span class="text-[10px] font-black text-red-400 px-2 py-0.5 rounded" style="background:rgba(248,113,113,0.15);border:1px solid rgba(248,113,113,0.4)">⚠ FALTA</span>'}
      </div>`;
    }).join('');
    return `<div class="mb-3 p-2.5 rounded-lg" style="background:rgba(0,0,0,0.18);border:1px dashed rgba(245,158,11,0.25)">
      <div class="text-[10px] uppercase tracking-wider text-amber-200/70 font-bold mb-2 px-1 flex items-center gap-1">
        <span>🎯</span><span>Metas y comisiones por zona</span>
      </div>
      <div class="space-y-1.5">${rows}</div>
    </div>`;
  }

  function _renderMetaChip(label, configKey, valor, unidad, color) {
    color = color || '#6366f1';
    const safeKey = String(configKey).replace(/'/g, '&#39;');
    return `<span class="meta-chip inline-flex items-center gap-2 px-3 py-1.5 rounded-lg cursor-pointer text-xs font-bold"
      onclick="MOS.editarMetaChip('${safeKey}', this)"
      data-meta-key="${safeKey}"
      data-meta-valor="${valor}"
      style="background:rgba(99,102,241,0.12);border:1px solid ${color};color:#c7d2fe;transition:all 0.2s;"
      title="Click para editar">
      <span class="text-[10px] opacity-80 uppercase">${label}</span>
      <span class="text-base font-black" style="color:${color}">${valor || '—'}</span>
      <span class="text-[10px] opacity-70">${unidad || ''}</span>
      <span class="text-[10px] opacity-50">✏️</span>
    </span>`;
  }

  function renderPersonal() {
    const cont = $('personalContenedor');
    if (!cont) return;

    const adminsMOS = (cfgData.personalMOS || []).filter(p => {
      const r = String(p.rol || '').toUpperCase();
      return r === 'MASTER' || r === 'ADMIN' || r === 'ADMINISTRADOR';
    });
    const operadoresWH = (cfgData.personal || []).filter(p =>
      String(p.rol || '').toUpperCase() !== 'SUPERVISOR'
    );

    // Contar online en cada grupo
    const _onlineCount = arr => arr.filter(p => _personaActividad(p.Ultima_Conexion || p.ultimaConexion).minutos < 5).length;
    const onlineMOS = _onlineCount(adminsMOS);
    const onlineWH  = _onlineCount(operadoresWH);
    // ME vendedores: contar dispositivos con sesión <5min cuyo Ultima_Sesion sea de un cajero
    const onlineME = (cfgData.dispositivos || []).filter(d => {
      if (String(d.Estado).toUpperCase() !== 'ACTIVO') return false;
      if (!d.Ultima_Sesion) return false;
      return _personaActividad(d.Ultima_Conexion).minutos < 5;
    }).length;

    // Metas (de cfgData.config si existe; si no, leerá vacío y guardará al editar)
    const cfg = (cfgData.config || {});
    // metaCajero ya no se muestra como chip global — cada zona se configura
    // por separado en _renderMetasPorZona (Infraestructura → modal Zona).
    const metaEnvasador  = cfg.evalMetaEnvasador  || '';
    const metaAlmacenero = cfg.evalMetaAlmacenero || '';
    const metaAuditorias = cfg.evalMetaAuditorias || '';
    const tarifaEnvasado = cfg.evalTarifaEnvasadoPorUnidad != null ? cfg.evalTarifaEnvasadoPorUnidad : '0.10';

    // ── Grupo 1: ADMIN/MASTER (MOS) ─────
    const grupoMOS = `<div class="card p-4" style="background:linear-gradient(135deg,#1e1b4b 0%,#0d1526 100%);border:1px solid #6366f1;">
      <div class="flex items-start justify-between gap-3 mb-3 flex-wrap">
        <div class="flex items-center gap-3">
          <span class="text-2xl">👑</span>
          <div>
            <div class="flex items-center gap-2">
              <h3 class="text-base font-black text-white">Administradores</h3>
              ${onlineMOS > 0 ? `<span class="badge text-[10px] disp-chip-live" style="background:rgba(16,185,129,0.18);color:#6ee7b7;border:1px solid rgba(16,185,129,0.5);">🟢 ${onlineMOS} online</span>` : ''}
            </div>
            <p class="text-[11px] text-slate-400 mt-0.5">MOS · acceso al panel · gestión global · ${adminsMOS.length} total</p>
          </div>
        </div>
        <button class="btn-primary text-xs px-3 py-1.5" onclick="MOS.abrirModalPersonal(null,'MOS')">+ admin</button>
      </div>
      ${adminsMOS.length === 0
        ? '<p class="text-center py-4 text-slate-500 text-sm">Sin admins/master registrados</p>'
        : `<div class="space-y-2">${adminsMOS.map(p => _renderPersonaCard(p, 'MOS')).join('')}</div>`}
    </div>`;

    // ── Grupo 2: VENDEDORES (ME) — usa el render de cajeros existente ─
    const grupoME = `<div class="card p-4" style="background:linear-gradient(135deg,#451a03 0%,#0d1526 100%);border:1px solid #f59e0b;">
      <div class="flex items-start justify-between gap-3 mb-3 flex-wrap">
        <div class="flex items-center gap-3">
          <span class="text-2xl">🛒</span>
          <div>
            <div class="flex items-center gap-2">
              <h3 class="text-base font-black text-white">Vendedores / Cajeros</h3>
              ${onlineME > 0 ? `<span class="badge text-[10px] disp-chip-live" style="background:rgba(16,185,129,0.18);color:#6ee7b7;border:1px solid rgba(16,185,129,0.5);">🟢 ${onlineME} online</span>` : ''}
            </div>
            <p class="text-[11px] text-slate-400 mt-0.5">MosExpress · cajeros que operan POS</p>
          </div>
        </div>
        <button class="btn-primary text-xs px-3 py-1.5" onclick="MOS.abrirModalPersonal(null,'mosExpress')">+ cajero/vendedor</button>
      </div>

      <!-- Metas y comisiones POR ZONA — cada zona se edita aparte (click → modal Zona) -->
      ${_renderMetasPorZona()}

      <div id="listMeCajeros" class="space-y-2"></div>
      <span id="cfgMeCajerosCount" class="hidden"></span>
    </div>`;

    // ── Grupo 3: OPERADORES WH (almacenero + envasador juntos) ─
    const grupoWH = `<div class="card p-4" style="background:linear-gradient(135deg,#0d1526 0%,#7c2d12 0%,#0d1526 100%);border:1px solid #ea580c;">
      <div class="flex items-start justify-between gap-3 mb-3 flex-wrap">
        <div class="flex items-center gap-3">
          <span class="text-2xl">🏭</span>
          <div>
            <div class="flex items-center gap-2">
              <h3 class="text-base font-black text-white">Operadores Almacén</h3>
              ${onlineWH > 0 ? `<span class="badge text-[10px] disp-chip-live" style="background:rgba(16,185,129,0.18);color:#6ee7b7;border:1px solid rgba(16,185,129,0.5);">🟢 ${onlineWH} online</span>` : ''}
            </div>
            <p class="text-[11px] text-slate-400 mt-0.5">warehouseMos · almaceneros + envasadores · ${operadoresWH.length} total</p>
          </div>
        </div>
        <div class="flex flex-wrap gap-1.5">
          ${_renderMetaChip('Meta guías', 'evalMetaAlmacenero', metaAlmacenero, '/día', '#ea580c')}
          ${_renderMetaChip('Tarifa envasado', 'evalTarifaEnvasadoPorUnidad', tarifaEnvasado, 'S/und', '#10b981')}
          ${_renderMetaChip('Auditorías almacén', 'evalMetaAuditorias', metaAuditorias, '/día', '#fbbf24')}
        </div>
        <button class="btn-primary text-xs px-3 py-1.5" onclick="MOS.abrirModalPersonal(null,'warehouseMos')">+ operador</button>
      </div>
      ${operadoresWH.length === 0
        ? '<p class="text-center py-4 text-slate-500 text-sm">Sin operadores registrados</p>'
        : `<div class="space-y-2">${operadoresWH.map(p => _renderPersonaCard(p, 'warehouseMos')).join('')}</div>`}
    </div>`;

    cont.innerHTML = grupoMOS + grupoME + grupoWH;

    // Renderizar cajeros ME (usa cache de liquidaciones existente)
    _cfgRenderMeCajeros();

    // Cargar audit log para mostrar última acción de cada admin (background)
    if (!_personalAuditCache.length) {
      API.get('getAuditoriaAdmin', { limit: 50 })
        .then(data => {
          if (Array.isArray(data)) {
            _personalAuditCache = data;
            renderPersonal(); // re-render para incluir últimas acciones
          }
        })
        .catch(_ => {});
    }
    // Actualizar badges
    _actualizarBadgesPersonal();
  }

  // Editar meta inline (chip → input → guardar al blur/enter)
  function editarMetaChip(configKey, chipEl) {
    const valorActual = chipEl.dataset.metaValor || '';
    const label = chipEl.querySelector('span:first-child')?.textContent || configKey;
    chipEl.outerHTML = `<span class="inline-flex items-center gap-2 px-2 py-1 rounded-lg" style="background:rgba(99,102,241,0.12);border:1px solid #6366f1;">
      <span class="text-[10px] text-slate-300 uppercase">${label}</span>
      <input type="number" id="metaInput_${configKey}" value="${valorActual}" autofocus
        onblur="MOS.guardarMetaChip('${configKey}', this.value)"
        onkeydown="if(event.key==='Enter')this.blur(); if(event.key==='Escape'){this.value='${valorActual}';this.blur();}"
        class="bg-slate-900 text-white text-sm font-black px-2 py-0.5 rounded border border-indigo-500 outline-none w-24"
        style="-moz-appearance:textfield;">
    </span>`;
    setTimeout(() => $('metaInput_' + configKey)?.focus(), 50);
  }

  // ────────────────────────────────────────────────────────
  // MODAL CLAVE GLOBAL (abierto desde card master/admin con 🔑)
  // ────────────────────────────────────────────────────────
  let _cgDataActual = null;

  function abrirModalClaveGlobal(idPersonal) {
    const p = (cfgData.personalMOS || []).find(x => x.idPersonal === idPersonal);
    if (!p) return;
    $('claveGlobalIdPersonal').value = p.idPersonal;
    $('claveGlobalRol').value = String(p.rol || '').toUpperCase();
    $('claveGlobalSubtitle').textContent = `${p.nombre} (${p.rol})`;
    $('claveGlobalPin').value = '';
    $('claveGlobalError').textContent = '';
    $('claveGlobalLogin').classList.remove('hidden');
    $('claveGlobalRevelada').classList.add('hidden');
    // Si es admin (no master), ocultar botón rotar
    const esMaster = String(p.rol || '').toUpperCase() === 'MASTER';
    const btnRotar = $('claveGlobalBtnRotar');
    if (btnRotar) btnRotar.style.display = esMaster ? '' : 'none';
    openModal('modalClaveGlobal');
    setTimeout(() => $('claveGlobalPin')?.focus(), 100);
  }

  async function cgConsultar() {
    const pin = String($('claveGlobalPin')?.value || '').trim();
    const err = $('claveGlobalError');
    if (!/^\d{4}$/.test(pin)) {
      if (err) err.textContent = 'PIN debe ser de 4 dígitos';
      return;
    }
    if (err) err.textContent = '';

    // 🚀 OPTIMISTA: revelar el panel YA con skeleton shimmer mientras llega
    // el fetch. Si el PIN falla, volvemos al login.
    const loginBox = $('claveGlobalLogin');
    const revBox   = $('claveGlobalRevelada');
    const digEl    = $('claveGlobalDigits');
    if (loginBox && revBox) {
      loginBox.classList.add('hidden');
      revBox.classList.remove('hidden');
      if (digEl) digEl.innerHTML = '<span class="cg-skel-pin cg-skel-pin-lg"></span>';
    }

    try {
      const data = await API.get('getClaveAdminGlobal', { pinAdmin: pin });
      if (!data?.autorizado) {
        // PIN malo → volver al login con error
        if (revBox) revBox.classList.add('hidden');
        if (loginBox) loginBox.classList.remove('hidden');
        if (err) err.textContent = data?.error || 'PIN incorrecto';
        $('claveGlobalPin').value = '';
        return;
      }
      _cgDataActual = data;
      _cgPintar(data);
      // Actualizar caché global del avatar menú
      if (typeof _segActualizarCacheLocal === 'function') _segActualizarCacheLocal(data);
    } catch(e) {
      if (revBox) revBox.classList.add('hidden');
      if (loginBox) loginBox.classList.remove('hidden');
      if (err) err.textContent = e?.message || 'Sin conexión';
    }
  }

  function _cgPintar(data) {
    $('claveGlobalDigits').textContent = (data.pin || '----').split('').join(' ');
    const dias = data.diasParaProximaRotacion;
    const dr = $('claveGlobalDias');
    if (data.vencida) { dr.textContent = '⚠ Vencida'; dr.style.color = '#f87171'; }
    else if (dias <= 5) { dr.textContent = dias + ' días'; dr.style.color = '#fbbf24'; }
    else { dr.textContent = dias + ' días'; dr.style.color = '#10b981'; }
    const pct = Math.max(0, Math.min(100, ((30 - dias) / 30) * 100));
    $('claveGlobalProgreso').style.width = pct + '%';
    if (data.fechaProximaRotacion) {
      const f = new Date(data.fechaProximaRotacion);
      $('claveGlobalFechaProxima').textContent = 'Próxima: ' + f.toLocaleDateString('es-PE', { day: 'numeric', month: 'long', year: 'numeric' });
    }
    $('claveGlobalLogin').classList.add('hidden');
    $('claveGlobalRevelada').classList.remove('hidden');
  }

  async function cgRotar() {
    const pin = String($('claveGlobalPin')?.value || '').trim();
    if (!/^\d{4}$/.test(pin)) {
      toast('PIN inválido', 'error'); return;
    }
    if (!confirm('¿Generar una nueva clave global aleatoria? La clave actual dejará de funcionar inmediatamente en MosExpress y warehouseMos.')) return;
    try {
      const data = await API.post('rotarClaveAdminGlobal', { manual: true, pinAdmin: pin });
      if (!data?.autorizado && data?.error) { toast(data.error, 'error'); return; }
      _cgDataActual = {
        pin: data.pin, fechaUltimaRotacion: data.fechaUltimaRotacion,
        fechaProximaRotacion: data.fechaProximaRotacion,
        diasDesdeRotacion: 0, diasParaProximaRotacion: 30, vencida: false
      };
      _cgPintar(_cgDataActual);
      if (typeof _segActualizarCacheLocal === 'function') _segActualizarCacheLocal(_cgDataActual);
      toast('Clave rotada · ' + data.pin, 'ok');
    } catch(e) {
      toast(e?.message || 'Error', 'error');
    }
  }

  // ────────────────────────────────────────────────────────
  // AUDITORÍA EXPANDIBLE EN CARD ADMIN
  // ────────────────────────────────────────────────────────
  function _togglePersAudit(idPersonal) {
    const safeId = String(idPersonal).replace(/'/g, '&#39;');
    const det = $('auditDetail_' + safeId);
    if (!det) return;
    if (det.classList.contains('hidden')) {
      det.classList.remove('hidden');
      _cargarAuditDetail(idPersonal);
    } else {
      det.classList.add('hidden');
    }
  }

  async function _cargarAuditDetail(idPersonal) {
    const list = $('auditList_' + idPersonal);
    if (!list) return;
    // Filtrar de cache si hay; si no, cargar
    const propiasHoy = _personalAuditCache.filter(a => {
      if (String(a.idPersonalAutoriza) !== String(idPersonal)) return false;
      const f = new Date(a.fecha);
      const hoy = new Date();
      return f.toDateString() === hoy.toDateString();
    });
    if (!propiasHoy.length) {
      list.innerHTML = '<div class="text-[10px] text-slate-600 italic">Sin acciones registradas hoy.</div>';
      return;
    }
    list.innerHTML = propiasHoy.slice(0, 8).map(a => {
      const f = a.fecha ? new Date(a.fecha) : null;
      const hora = f ? f.toLocaleTimeString('es-PE', { hour: '2-digit', minute: '2-digit' }) : '—';
      const accColor = {
        'ANULACION': 'text-red-400', 'CREDITO': 'text-amber-400', 'CAMBIO_METODO': 'text-blue-400',
        'REABRIR_GUIA': 'text-purple-400', 'DESBLOQUEO_USUARIO': 'text-emerald-400', 'ROTACION_PIN_GLOBAL': 'text-pink-400'
      }[String(a.accion || '').toUpperCase()] || 'text-slate-400';
      return `<div class="flex items-center gap-2">
        <span class="text-slate-600 text-[10px]">${hora}</span>
        <span class="${accColor} font-bold uppercase tracking-wider text-[10px]">${a.accion || '—'}</span>
        <span class="text-slate-500 truncate flex-1">${a.refDocumento || ''}</span>
      </div>`;
    }).join('');
  }

  // ────────────────────────────────────────────────────────
  // MODAL HISTORIAL COMPLETO DE AUDITORÍA (agrupado por fecha)
  // ────────────────────────────────────────────────────────
  let _histAuditFiltroPersonal = null;

  function abrirModalHistorialAudit(idPersonal, nombre) {
    _histAuditFiltroPersonal = idPersonal || null;
    $('histAuditSubtitle').textContent = nombre ? `Acciones de ${nombre}` : 'Todas las acciones';
    $('histAuditFiltroAccion').value = '';
    openModal('modalHistorialAudit');
    histAuditCargar();
  }

  async function histAuditCargar() {
    const cont = $('histAuditContenido');
    if (!cont) return;
    cont.innerHTML = '<div class="text-center py-8 text-slate-500 text-sm">Cargando...</div>';
    try {
      const data = await API.get('getAuditoriaAdmin', { limit: 200 });
      _personalAuditCache = Array.isArray(data) ? data : [];
      histAuditFiltrar();
    } catch(e) {
      cont.innerHTML = '<div class="text-center py-6 text-red-400 text-sm">Error: ' + e.message + '</div>';
    }
  }

  function histAuditFiltrar() {
    const cont = $('histAuditContenido');
    if (!cont) return;
    let rows = _personalAuditCache.slice();
    if (_histAuditFiltroPersonal) {
      rows = rows.filter(a => String(a.idPersonalAutoriza) === String(_histAuditFiltroPersonal));
    }
    const filtroAcc = $('histAuditFiltroAccion')?.value || '';
    if (filtroAcc) rows = rows.filter(a => String(a.accion || '').toUpperCase() === filtroAcc);
    if (!rows.length) {
      cont.innerHTML = '<div class="text-center py-8 text-slate-500 text-sm">Sin registros para los filtros aplicados.</div>';
      return;
    }
    // Agrupar por fecha
    const grupos = {};
    rows.forEach(a => {
      const f = a.fecha ? new Date(a.fecha) : null;
      const key = f ? f.toISOString().substring(0, 10) : '—';
      if (!grupos[key]) grupos[key] = [];
      grupos[key].push(a);
    });
    const keys = Object.keys(grupos).sort().reverse();
    cont.innerHTML = keys.map(k => {
      const f = new Date(k);
      const lbl = isNaN(f.getTime()) ? k : f.toLocaleDateString('es-PE', { weekday: 'short', day: 'numeric', month: 'short', year: 'numeric' });
      const acciones = grupos[k];
      return `<div class="card p-3" style="background:#0d1526;border:1px solid #1e293b;">
        <div class="flex items-center justify-between mb-2">
          <div class="text-xs font-bold text-white uppercase">${lbl}</div>
          <span class="badge badge-gray text-[9px]">${acciones.length} acción${acciones.length === 1 ? '' : 'es'}</span>
        </div>
        <div class="space-y-1.5">
          ${acciones.map(a => {
            const fa = a.fecha ? new Date(a.fecha) : null;
            const hora = fa ? fa.toLocaleTimeString('es-PE', { hour: '2-digit', minute: '2-digit' }) : '—';
            const accColor = {
              'ANULACION': '#f87171', 'CREDITO': '#fbbf24', 'CAMBIO_METODO': '#60a5fa',
              'REABRIR_GUIA': '#a78bfa', 'DESBLOQUEO_USUARIO': '#34d399', 'ROTACION_PIN_GLOBAL': '#f472b6'
            }[String(a.accion || '').toUpperCase()] || '#94a3b8';
            return `<div class="flex items-center gap-2 text-[11px] py-1 px-2 rounded" style="background:#0a1424;">
              <span class="text-slate-500 font-mono">${hora}</span>
              <span class="font-bold uppercase tracking-wider" style="color:${accColor}">${a.accion || '—'}</span>
              <span class="text-slate-300 flex-1 truncate">${a.nombreAutoriza || '—'}</span>
              <span class="text-slate-500 text-[10px] hidden sm:inline">${a.appOrigen || ''}</span>
              <span class="text-slate-500 text-[10px] font-mono truncate hidden md:inline" style="max-width:120px;">${a.refDocumento || ''}</span>
            </div>`;
          }).join('')}
        </div>
      </div>`;
    }).join('');
  }

  // ────────────────────────────────────────────────────────
  // MODAL INTEGRIDAD (alertas)
  // ────────────────────────────────────────────────────────
  function abrirModalIntegridad() {
    openModal('modalIntegridad');
    if (typeof renderIntegridad === 'function') renderIntegridad();
  }

  // ────────────────────────────────────────────────────────
  // MODAL NOTIFICACIONES UNIFICADAS
  // ────────────────────────────────────────────────────────
  function abrirModalNotificaciones() {
    openModal('modalNotificaciones');
    _renderNotificaciones();
  }

  function _renderNotificaciones() {
    const cont = $('notifContenido');
    if (!cont) return;
    const partes = [];
    let total = 0;

    // 1) Dispositivos pendientes
    const pendDisp = (cfgData.dispositivos || []).filter(d => String(d.Estado).toUpperCase() === 'PENDIENTE_APROBACION');
    if (pendDisp.length) {
      total += pendDisp.length;
      partes.push(`<div class="card p-3" style="background:#3b1010;border:1px solid #ef4444;">
        <div class="flex items-center gap-2 mb-2">
          <span class="text-xl">📱</span>
          <strong class="text-white text-sm">Dispositivos esperando aprobación</strong>
          <span class="badge badge-red text-[10px] ml-auto">${pendDisp.length}</span>
        </div>
        <div class="space-y-1.5">
          ${pendDisp.slice(0, 5).map(d => `<div class="text-[11px] text-slate-300 px-2 py-1 rounded flex items-center gap-1.5 flex-wrap" style="background:#0a1424;">
            <span>${_dispIcono(d.Nombre_Equipo)} ${d.Nombre_Equipo || 'Nuevo'}</span>
            ${_appBadge(d.App, { compact: false })}
            <span class="text-slate-600">·</span>
            <span class="text-slate-500 font-mono">${String(d.ID_Dispositivo).substring(0, 8)}...</span>
          </div>`).join('')}
        </div>
        <button onclick="MOS.closeModal('modalNotificaciones');MOS.nav('config');MOS.setCfgTab('infra')" class="mt-2 text-[10px] text-red-300 hover:text-red-200">Ver en Infraestructura →</button>
      </div>`);
    }

    // 2) Bloqueos vendedores ME activos
    const bloqs = (cfgData.bloqueosME || []).filter(b => b.fechaBloqueo && !b.unlockVigente);
    if (bloqs.length) {
      total += bloqs.length;
      partes.push(`<div class="card p-3" style="background:#3b2410;border:1px solid #f59e0b;">
        <div class="flex items-center gap-2 mb-2">
          <span class="text-xl">🔒</span>
          <strong class="text-white text-sm">Cajeros bloqueados</strong>
          <span class="badge badge-yellow text-[10px] ml-auto">${bloqs.length}</span>
        </div>
        <div class="space-y-1.5">
          ${bloqs.slice(0, 5).map(b => `<div class="text-[11px] text-slate-300 px-2 py-1 rounded" style="background:#0a1424;">
            👤 ${b.nombre} <span class="text-slate-600">·</span> <span class="text-slate-500">${b.motivo || ''}</span>
          </div>`).join('')}
        </div>
      </div>`);
    }

    // 3) Integridad alertas
    if (_personalIntegCount > 0) {
      total += _personalIntegCount;
      partes.push(`<div class="card p-3" style="background:#3b1010;border:1px solid #dc2626;">
        <div class="flex items-center gap-2 mb-2">
          <span class="text-xl">🛡️</span>
          <strong class="text-white text-sm">Integridad de catálogo</strong>
          <span class="badge badge-red text-[10px] ml-auto">${_personalIntegCount}</span>
        </div>
        <p class="text-[11px] text-slate-400">Hay alertas de seguridad en PRODUCTOS_MASTER o EQUIVALENCIAS.</p>
        <button onclick="MOS.closeModal('modalNotificaciones');MOS.abrirModalIntegridad()" class="mt-2 text-[10px] text-red-300 hover:text-red-200">Revisar →</button>
      </div>`);
    }

    if (total === 0) {
      cont.innerHTML = `<div class="text-center py-12 text-slate-500">
        <div class="text-5xl mb-3">✨</div>
        <p class="font-bold text-emerald-400">Todo en orden</p>
        <p class="text-xs">Sin notificaciones pendientes.</p>
      </div>`;
      $('notifSubtitle').textContent = 'Sin pendientes';
    } else {
      cont.innerHTML = partes.join('');
      $('notifSubtitle').textContent = `${total} pendiente${total === 1 ? '' : 's'}`;
    }
  }

  // ────────────────────────────────────────────────────────
  // MODAL ENVIAR PUSH a usuario
  // ────────────────────────────────────────────────────────
  function abrirModalEnviarPush(idPersonal, nombre) {
    $('pushDestinoUsuario').value = nombre || '';
    $('pushDestinoNombre').textContent = `a ${nombre || 'usuario'}`;
    $('pushTitulo').value = '📢 Mensaje del admin';
    $('pushCuerpo').value = '';
    openModal('modalEnviarPush');
    setTimeout(() => $('pushCuerpo')?.focus(), 100);
  }

  async function enviarPushUsuario() {
    const titulo = String($('pushTitulo')?.value || '').trim();
    const cuerpo = String($('pushCuerpo')?.value || '').trim();
    const dest = String($('pushDestinoUsuario')?.value || '').trim();
    if (!titulo || !cuerpo) { toast('Título y mensaje son requeridos', 'error'); return; }
    if (!dest) { toast('Destinatario no encontrado', 'error'); return; }
    closeModal('modalEnviarPush');
    try {
      const r = await API.post('enviarPushUsuario', { usuario: dest, titulo, cuerpo });
      if (r?.tokensAlcanzados) {
        toast(`✓ Mensaje enviado a ${dest} (${r.tokensAlcanzados} dispositivo${r.tokensAlcanzados === 1 ? '' : 's'})`, 'ok');
      } else {
        toast(`✓ Mensaje enviado a ${dest}`, 'ok');
      }
    } catch(e) {
      // Si el usuario no tiene tokens, mostrar error claro
      const msg = e?.message || 'Error';
      if (msg.includes('no tiene dispositivos')) {
        toast(`⚠ ${dest} no tiene notificaciones activas. Pídele que las habilite al iniciar sesión.`, 'warn', 8000);
      } else {
        toast('Error: ' + msg, 'error');
      }
    }
  }

  // ────────────────────────────────────────────────────────
  // ACTUALIZAR BADGES (notif + integridad) en header de Personal
  // ────────────────────────────────────────────────────────
  async function _actualizarBadgesPersonal() {
    // Notificaciones unificadas
    const pendDisp = (cfgData.dispositivos || []).filter(d => String(d.Estado).toUpperCase() === 'PENDIENTE_APROBACION').length;
    const bloqs = (cfgData.bloqueosME || []).filter(b => b.fechaBloqueo && !b.unlockVigente).length;
    _personalNotifCount = pendDisp + bloqs + _personalIntegCount;
    const bN = $('personalNotifBadge');
    if (bN) {
      if (_personalNotifCount > 0) {
        bN.classList.remove('hidden');
        bN.textContent = _personalNotifCount;
      } else {
        bN.classList.add('hidden');
      }
    }
    // Integridad
    try {
      const r = await API.get('getAuditoriaIntegridad', {});
      const alertas = r?.alertas || r?.data || [];
      _personalIntegCount = Array.isArray(alertas) ? alertas.filter(a => !a.resuelto).length : 0;
    } catch(_) { _personalIntegCount = 0; }
    const bI = $('personalIntegBadge');
    if (bI) {
      if (_personalIntegCount > 0) {
        bI.classList.remove('hidden');
        bI.textContent = _personalIntegCount;
      } else {
        bI.classList.add('hidden');
      }
    }
  }

  async function guardarMetaChip(configKey, valor) {
    const v = String(valor || '').trim();
    if (!cfgData.config) cfgData.config = {};
    cfgData.config[configKey] = v;
    renderPersonal();
    try {
      await API.post('setConfig', { clave: configKey, valor: v });
      toast(`Meta actualizada · ${configKey} = ${v}`, 'ok');
    } catch(e) {
      toast('Error al guardar meta: ' + e.message, 'error');
    }
  }

  // Pinta el card "🛒 Vendedores — MosExpress" en Config → Personal.
  // Lee del cache localStorage de liquidaciones pendientes (mismo source
  // que la pantalla de Liquidaciones, ya prefetcheado al login).
  function _cfgRenderMeCajeros() {
    const cont = $('listMeCajeros');
    if (!cont) return;
    let pendientes = null;
    try {
      const raw = localStorage.getItem('mos_liq_pendientes');
      if (raw) {
        const p = JSON.parse(raw);
        pendientes = p && p.data;
      }
    } catch {}

    let cajeros = (pendientes && Array.isArray(pendientes.personal))
      ? pendientes.personal.filter(p => {
          const app = String(p.appOrigen || '').toLowerCase();
          return app === 'mosexpress' || app === 'mexpress' || app.indexOf('express') >= 0;
        })
      : [];
    // Agregar bloqueados que no aparecen en jornadas de la semana
    const _normN = s => String(s || '').trim().toLowerCase();
    const yaListados = new Set(cajeros.map(c => _normN(c.nombre)));
    (cfgData.bloqueosME || []).forEach(b => {
      if (!yaListados.has(_normN(b.nombre))) {
        cajeros.push({
          nombre: b.nombre,
          rol: 'CAJERO',
          appOrigen: 'mosExpress',
          montoTotal: 0, diasPendientes: 0, diasAuditados: 0,
          esVirtual: false
        });
      }
    });

    const cnt = $('cfgMeCajerosCount');
    if (cnt) {
      cnt.textContent = cajeros.length + (cajeros.length === 1 ? ' activo' : ' activos');
      cnt.className = 'badge ' + (cajeros.length ? 'badge-green' : 'badge-gray') + ' text-xs';
    }
    if (!cajeros.length) {
      cont.innerHTML = '<p class="text-xs text-slate-500 italic text-center py-3">Sin cajeros activos esta semana.</p>';
      return;
    }
    // Map por nombre normalizado: el bloqueo vive en BLOQUEOS_USUARIO (no toca PERSONAL_MASTER)
    const _norm = s => String(s || '').trim().toLowerCase();
    const bloqMap = {};
    (cfgData.bloqueosME || []).forEach(b => { bloqMap[_norm(b.nombre)] = b; });

    // Cruzar con DISPOSITIVOS para detectar última conexión + zona principal
    // del cajero (via Ultima_Zona del dispositivo donde tiene Ultima_Sesion).
    const dispPorCajero = {};
    (cfgData.dispositivos || []).forEach(d => {
      if (String(d.Estado).toUpperCase() !== 'ACTIVO') return;
      const sesNorm = _norm(d.Ultima_Sesion);
      if (!sesNorm) return;
      const t = new Date(d.Ultima_Conexion || 0).getTime() || 0;
      const prev = dispPorCajero[sesNorm];
      if (!prev || (new Date(prev.Ultima_Conexion || 0).getTime() || 0) < t) {
        dispPorCajero[sesNorm] = d;
      }
    });

    // Agrupar cajeros por zona inferida (Ultima_Zona del dispositivo)
    // Si no tiene dispositivo / Ultima_Zona → grupo "Sin zona"
    const grupos = {};
    cajeros.forEach(c => {
      const disp = dispPorCajero[_norm(c.nombre)];
      const zonaId = String(disp?.Ultima_Zona || '').trim() || '__SIN_ZONA__';
      if (!grupos[zonaId]) grupos[zonaId] = [];
      grupos[zonaId].push(c);
    });

    // Función render de una persona (común a todos los grupos)
    const renderPersona = (c) => {
      const initials = String(c.nombre || '?').split(/\s+/).map(s => s[0] || '').join('').slice(0, 2).toUpperCase();
      const monto = parseFloat(c.montoTotal) || 0;
      const dias = parseInt(c.diasPendientes) || 0;
      const aud  = parseInt(c.diasAuditados) || 0;
      const virt = c.esVirtual
        ? '<span class="badge badge-yellow text-[9px] ml-1" title="Detectado de ventas (no en PERSONAL_MASTER)">virtual</span>'
        : '';
      const reg = bloqMap[_norm(c.nombre)];
      const bloqueado = !!(reg && reg.fechaBloqueo && !reg.unlockVigente);
      const safeNombre = String(c.nombre || '').replace(/'/g, '&#39;');
      // Indicador de actividad cruzando con DISPOSITIVOS
      const dispActivo = dispPorCajero[_norm(c.nombre)];
      const act = dispActivo ? _personaActividad(dispActivo.Ultima_Conexion) : { color: '#64748b', label: 'sin sesión', dot: '⚫', minutos: Infinity };
      const isFresh = act.minutos < 5;
      const opacity = bloqueado ? 'opacity:0.6;' : '';
      const borderCol = bloqueado ? '#7f1d1d' : (isFresh ? 'rgba(16,185,129,0.5)' : '#1e293b');
      const bgChip = isFresh ? 'rgba(16,185,129,0.06)' : '#0d1526';
      const dotPulse = isFresh ? '<span class="disp-dot-pulse"></span>' : '';
      const claseFresh = isFresh ? 'disp-chip-live' : '';
      const lockBadge = bloqueado
        ? '<span class="badge badge-red text-[9px] ml-1" title="Cajero bloqueado — al iniciar MosExpress con este nombre, ve pantalla de candado">🔒 bloqueado</span>'
        : '';
      return `<div class="flex items-center gap-3 p-3 rounded-lg ${claseFresh}" style="background:${bgChip};border:1px solid ${borderCol};${opacity}transition:all 0.2s;">
        <div class="relative shrink-0">
          <div class="w-10 h-10 rounded-full flex items-center justify-center text-sm font-bold"
               style="background:linear-gradient(135deg,#fbbf24,#f59e0b);color:#0b1220">${initials}</div>
          ${dotPulse}
        </div>
        <div class="flex-1 min-w-0">
          <div class="font-medium text-sm text-slate-200 truncate">${c.nombre}${virt}${lockBadge}</div>
          <div class="flex items-center gap-2 mt-0.5 flex-wrap">
            <span class="badge badge-gray text-[9px] uppercase">${c.rol || 'CAJERO'}</span>
            <span class="text-[9px]" style="color:${act.color};">${act.dot} ${act.label}</span>
            <span class="text-[9px] text-slate-500">${dias}d · ${aud}/${dias} aud</span>
          </div>
        </div>
        <div class="text-right shrink-0 mr-2">
          <div class="text-sm font-bold text-amber-400">S/ ${monto.toFixed(2)}</div>
          <div class="text-[10px] text-slate-500">esta semana</div>
        </div>
        <button onclick="event.stopPropagation();MOS.abrirEspiaPorUsuario('${safeNombre}')"
                class="shrink-0 w-8 h-8 rounded-full flex items-center justify-center hover:scale-110 transition-all"
                style="background:rgba(99,102,241,0.18);border:1px solid rgba(99,102,241,0.5);color:#a5b4fc;font-size:13px;"
                title="Espiar a ${c.nombre} (audio + GPS)">🕵️</button>
        <button onclick="event.stopPropagation();MOS.abrirModalEnviarPush('','${safeNombre}')"
                class="shrink-0 w-8 h-8 rounded-full flex items-center justify-center hover:scale-110 transition-all"
                style="background:rgba(59,130,246,0.15);border:1px solid rgba(59,130,246,0.5);color:#60a5fa;font-size:13px;"
                title="Enviar mensaje push a ${c.nombre}">💬</button>
        <label class="pers-switch shrink-0" title="${bloqueado ? 'Activar cajero — desbloquea pantalla de candado en su dispositivo' : 'Bloquear cajero — solo el dispositivo donde está logueado verá pantalla de candado'}">
          <input type="checkbox" ${bloqueado ? '' : 'checked'} onchange="MOS.toggleVendedorME('${safeNombre}', event)">
          <span class="pers-switch-slider"></span>
        </label>
      </div>`;
    };

    // Render por grupo (zona). Ordena las zonas alfabéticamente y deja
    // "Sin zona" al final.
    const zonaNombres = {};
    (cfgData.zonas || []).forEach(z => { zonaNombres[String(z.idZona)] = z.nombre || z.idZona; });
    const keys = Object.keys(grupos).sort((a,b) => {
      if (a === '__SIN_ZONA__') return 1;
      if (b === '__SIN_ZONA__') return -1;
      return (zonaNombres[a] || a).localeCompare(zonaNombres[b] || b);
    });
    cont.innerHTML = keys.map(zKey => {
      const lista = grupos[zKey];
      const nombreZona = zKey === '__SIN_ZONA__' ? '🌫 Sin zona asignada' : ('🏬 ' + (zonaNombres[zKey] || zKey));
      const rolesEnGrupo = {};
      lista.forEach(c => {
        const r = (c.rol || 'CAJERO').toUpperCase();
        rolesEnGrupo[r] = (rolesEnGrupo[r] || 0) + 1;
      });
      const desgloseRol = Object.keys(rolesEnGrupo)
        .map(r => `${rolesEnGrupo[r]} ${r.toLowerCase()}${rolesEnGrupo[r] !== 1 ? 's' : ''}`)
        .join(' · ');
      return `<div class="mb-3">
        <div class="flex items-center justify-between px-1 mb-1.5">
          <span class="text-[10px] uppercase tracking-wider text-amber-300/70 font-bold">${nombreZona}</span>
          <span class="text-[10px] text-slate-500">${desgloseRol}</span>
        </div>
        <div class="space-y-2">${lista.map(renderPersona).join('')}</div>
      </div>`;
    }).join('');
  }

  // Activa/bloquea un vendedor ME por NOMBRE en BLOQUEOS_USUARIO
  // (no toca PERSONAL_MASTER — los cajeros ME comparten el usuario plantilla)
  async function toggleVendedorME(nombre, ev) {
    if (ev) ev.stopPropagation();
    const checked = ev?.target?.checked;
    // checked=true → activar (sin bloqueo) ; checked=false → bloquear
    const accion = checked ? 'activar' : 'BLOQUEAR (mostrar pantalla de candado en su dispositivo)';
    if (!confirm(`¿${accion.charAt(0).toUpperCase() + accion.slice(1)} a ${nombre}?\n\nSolo afecta al dispositivo donde "${nombre}" esté logueado en MosExpress. Otros cajeros siguen vendiendo normal.`)) {
      if (ev?.target) ev.target.checked = !checked;
      return;
    }
    try {
      await API.post('bloquearVendedorME', {
        nombre: nombre,
        appOrigen: 'mosExpress',
        bloquear: !checked,
        bloqueadoPor: S.session?.nombre || 'admin'
      });
      toast(`${nombre} ${checked ? 'activado' : 'bloqueado'} ✓`, 'ok');
      // Refrescar lista de bloqueos
      const bloq = await API.get('getVendedoresMEBloqueados', {});
      cfgData.bloqueosME = bloq || [];
      _cfgRenderMeCajeros();
    } catch(e) {
      console.error('[toggleVendedorME]', e);
      toast('Error: ' + e.message, 'error');
      if (ev?.target) ev.target.checked = !checked;
    }
  }

  // (renderSeries() obsoleto — series ahora viven dentro de Infraestructura como chips)

  function renderSeguridad() {
    // Reset panel a estado login
    seg_ocultar();
    // Renderizar lista de admins (de cfgData.usuarios MOS o llamar API)
    const listaEl = $('segListaAdmins');
    if (listaEl) {
      const admins = (cfgData.personalMOS || []).filter(u => {
        const r = String(u.rol || '').toUpperCase();
        return (r === 'MASTER' || r === 'ADMIN' || r === 'ADMINISTRADOR') && String(u.estado) === '1';
      });
      if (!admins.length) {
        listaEl.innerHTML = '<p class="text-slate-500 text-sm text-center py-4">Sin admins activos. Crea uno en pestaña Personal.</p>';
      } else {
        listaEl.innerHTML = admins.map(a => `
          <div class="flex items-center gap-3 p-3 rounded-lg" style="background:#0d1526;border:1px solid #1e293b;">
            <div class="w-9 h-9 rounded-full flex items-center justify-center text-white font-bold text-sm" style="background:${a.color || '#6366f1'}">
              ${(a.nombre || '?')[0]}${(a.apellido || '')[0] || ''}
            </div>
            <div class="flex-1 min-w-0">
              <div class="text-sm font-medium text-slate-200 truncate">${a.nombre} ${a.apellido || ''}</div>
              <div class="text-xs text-slate-500 uppercase tracking-wider">${a.rol}</div>
            </div>
          </div>
        `).join('');
      }
    }
  }

  // ── Seguridad: Clave Admin Global ──────────────────────
  let _segDataActual = null;

  function seg_ocultar() {
    const login = $('segPanelLogin');
    const clave = $('segPanelClave');
    if (login) login.classList.remove('hidden');
    if (clave) clave.classList.add('hidden');
    const inp = $('segPinAdmin');
    if (inp) inp.value = '';
    const err = $('segError');
    if (err) err.textContent = '';
    _segDataActual = null;
  }

  async function seg_consultarClave() {
    const inp = $('segPinAdmin');
    const err = $('segError');
    const pin = String(inp?.value || '').trim();
    if (!/^\d{4}$/.test(pin)) {
      if (err) err.textContent = 'Ingresa tu PIN de 4 dígitos';
      return;
    }
    if (err) err.textContent = '';
    try {
      const data = await API.get('getClaveAdminGlobal', { pinAdmin: pin });
      if (!data?.autorizado) {
        if (err) err.textContent = data?.error || 'PIN incorrecto';
        if (inp) inp.value = '';
        return;
      }
      _segDataActual = data;
      _segActualizarCacheLocal(data);
      _segPintar(data);
      seg_cargarAuditoria();
    } catch(e) {
      console.error('[seg_consultarClave]', e);
      if (err) err.textContent = e?.message || 'Sin conexión';
    }
  }

  function _segPintar(data) {
    const claveDig = $('segClaveDigits');
    if (claveDig) claveDig.textContent = (data.pin || '----').split('').join(' ');
    const dr = $('segDiasRestantes');
    if (dr) {
      const dias = data.diasParaProximaRotacion;
      dr.textContent = data.vencida ? '⚠ Vencida — rota ahora'
                       : (dias === 0 ? 'Hoy' : (dias + ' días'));
      dr.style.color = data.vencida ? '#f87171' : (dias <= 5 ? '#fbbf24' : '#10b981');
    }
    const barra = $('segBarraProgreso');
    if (barra) {
      const pct = Math.max(0, Math.min(100, ((30 - data.diasParaProximaRotacion) / 30) * 100));
      barra.style.width = pct + '%';
      if (data.vencida) barra.style.background = '#ef4444';
    }
    const fp = $('segFechaProxima');
    if (fp && data.fechaProximaRotacion) {
      const f = new Date(data.fechaProximaRotacion);
      fp.textContent = 'Próxima rotación: ' + f.toLocaleDateString('es-PE', { day: 'numeric', month: 'long', year: 'numeric' });
    }
    $('segPanelLogin')?.classList.add('hidden');
    $('segPanelClave')?.classList.remove('hidden');
  }

  async function seg_rotarManual() {
    const inp = $('segPinAdmin');
    const pin = String(inp?.value || '').trim();
    let pinUsar = pin;
    if (!/^\d{4}$/.test(pinUsar)) {
      pinUsar = prompt('Ingresa tu PIN admin de 4 dígitos para confirmar la rotación:');
      if (!pinUsar || !/^\d{4}$/.test(pinUsar.trim())) {
        toast('Rotación cancelada · PIN inválido', 'warn');
        return;
      }
      pinUsar = pinUsar.trim();
    }
    if (!confirm('¿Generar una nueva clave global aleatoria? La clave actual dejará de funcionar inmediatamente en MosExpress y warehouseMos.')) return;
    try {
      const data = await API.post('rotarClaveAdminGlobal', { manual: true, pinAdmin: pinUsar });
      if (!data?.autorizado && data?.error) { toast(data.error, 'danger'); return; }
      _segDataActual = {
        pin: data.pin,
        fechaUltimaRotacion: data.fechaUltimaRotacion,
        fechaProximaRotacion: data.fechaProximaRotacion,
        diasDesdeRotacion: 0,
        diasParaProximaRotacion: 30,
        vencida: false
      };
      _segActualizarCacheLocal(_segDataActual);
      _segPintar(_segDataActual);
      seg_cargarAuditoria();
      toast('Clave rotada · ' + data.pin, 'ok', 5000);
    } catch(e) {
      console.error('[seg_rotarManual]', e);
      toast(e?.message || 'Sin conexión', 'danger');
    }
  }

  async function seg_cargarAuditoria() {
    const tbody = $('tbodyAuditoria');
    if (!tbody) return;
    tbody.innerHTML = '<tr><td colspan="5" class="text-center py-4 text-slate-500">Cargando...</td></tr>';
    try {
      const data = await API.get('getAuditoriaAdmin', { limit: 30 });
      if (!Array.isArray(data)) {
        tbody.innerHTML = '<tr><td colspan="5" class="text-center py-4 text-slate-500">Sin auditoría disponible.</td></tr>';
        return;
      }
      if (!data.length) {
        tbody.innerHTML = '<tr><td colspan="5" class="text-center py-6 text-slate-500">Aún no hay acciones registradas.</td></tr>';
        return;
      }
      tbody.innerHTML = data.map(a => {
        const fecha = a.fecha ? new Date(a.fecha) : null;
        const fmtFecha = fecha ? fecha.toLocaleDateString('es-PE', { day: '2-digit', month: '2-digit' }) + ' ' + fecha.toLocaleTimeString('es-PE', { hour: '2-digit', minute: '2-digit' }) : '—';
        const accColor = {
          'ANULACION': 'text-red-400',
          'CREDITO': 'text-amber-400',
          'CAMBIO_METODO': 'text-blue-400',
          'REABRIR_GUIA': 'text-purple-400',
          'DESBLOQUEO_USUARIO': 'text-emerald-400',
          'ROTACION_PIN_GLOBAL': 'text-pink-400'
        }[String(a.accion || '').toUpperCase()] || 'text-slate-400';
        return `<tr>
          <td class="text-slate-500">${fmtFecha}</td>
          <td class="${accColor} font-semibold text-xs uppercase tracking-wider">${a.accion || '—'}</td>
          <td class="text-slate-200">${a.nombreAutoriza || '—'}</td>
          <td class="text-slate-500 text-xs">${a.appOrigen || '—'}</td>
          <td class="text-slate-500 text-xs hidden sm:table-cell font-mono">${a.refDocumento || '—'}</td>
        </tr>`;
      }).join('');
    } catch(e) {
      tbody.innerHTML = '<tr><td colspan="5" class="text-center py-4 text-slate-500">Sin conexión</td></tr>';
    }
  }

  // (renderDispositivos() obsoleto — ahora viven dentro de Infraestructura)
  // Helpers compartidos para iconos / actividad de dispositivos
  function _dispIcono(nombre) {
    const n = String(nombre || '').toLowerCase();
    if (n.includes('tablet') || n.includes('ipad'))      return '📲';
    if (n.includes('celular') || n.includes('movil') || n.includes('phone')) return '📱';
    if (n.includes('laptop') || n.includes('notebook'))  return '💻';
    if (n.includes('pc ') || n.startsWith('pc') || n.includes('desktop')) return '🖥️';
    return '📱';
  }

  // Pill con la app de origen del dispositivo (ME / WH / MOS) — útil para que
  // el admin sepa de qué cliente viene la solicitud antes de aprobar.
  function _appBadge(appRaw, opts) {
    const app = String(appRaw || '').toLowerCase();
    let icon = '❓', label = 'desconocida', bg = 'rgba(148,163,184,0.15)', border = '#475569', fg = '#cbd5e1';
    if (app === 'mosexpress' || app === 'me' || app.indexOf('express') >= 0) {
      icon = '🛒'; label = 'MosExpress'; bg = 'rgba(16,185,129,0.15)'; border = '#10b981'; fg = '#6ee7b7';
    } else if (app === 'warehousemos' || app === 'wh' || app.indexOf('warehouse') >= 0) {
      icon = '📦'; label = 'warehouseMos'; bg = 'rgba(251,146,60,0.15)'; border = '#fb923c'; fg = '#fdba74';
    } else if (app === 'mos') {
      icon = '👑'; label = 'MOS panel'; bg = 'rgba(168,85,247,0.15)'; border = '#a855f7'; fg = '#d8b4fe';
    } else if (!app || app === '') {
      icon = '❓'; label = '?';
    }
    const compact = opts && opts.compact;
    const cls = compact ? 'text-[9px] px-1.5 py-0.5' : 'text-[10px] px-2 py-0.5';
    return `<span class="${cls} rounded font-bold inline-flex items-center gap-1" style="background:${bg};border:1px solid ${border};color:${fg};white-space:nowrap;">${icon} ${compact ? '' : label}</span>`;
  }

  function _dispActividad(ultimaConexion) {
    if (!ultimaConexion) return { color: '#64748b', label: 'sin conexión', dot: '⚫', minutos: Infinity };
    const t = _parseTsUtc(ultimaConexion);
    if (isNaN(t)) return { color: '#64748b', label: ultimaConexion, dot: '⚫', minutos: Infinity };
    const seg = Math.floor((Date.now() - t) / 1000);
    const min = Math.floor(seg / 60);
    if (seg < 0)       return { color: '#10b981', label: '🔴 LIVE · ahora', dot: '🟢', minutos: 0 };
    if (seg < 90)      return { color: '#10b981', label: `🔴 LIVE · hace ${seg}s`, dot: '🟢', minutos: min };
    if (min < 5)       return { color: '#10b981', label: `online · hace ${min}m`,  dot: '🟢', minutos: min };
    if (min < 60)      return { color: '#10b981', label: `hace ${min}m`,     dot: '🟢', minutos: min };
    if (min < 60*24)   return { color: '#fbbf24', label: `hace ${Math.floor(min/60)}h`, dot: '🟡', minutos: min };
    if (min < 60*24*7) return { color: '#f97316', label: `hace ${Math.floor(min/60/24)}d`, dot: '🟠', minutos: min };
    return { color: '#ef4444', label: `inactivo ${Math.floor(min/60/24)}d`, dot: '🔴', minutos: min };
  }

  // Tracking de movimientos entre renders para animar transiciones
  let _dispUltimaEstacionMap = {};
  let _dispRenderCount = 0;
  // Trails: fantasmas que se quedan 5s en la estación de origen tras un movimiento
  let _dispFantasmas = {}; // { deviceId: { desde, hacia, ico, nombre, expira } }
  let _dispCleanupTimer = null;
  // Modo heatmap: colorea estaciones según cantidad de dispositivos online
  let _infraHeatmapActivo = false;

  // Devuelve dispositivos cuya ÚLTIMA sesión fue en esta estación
  // (sin importar cuánto tiempo, mantiene "viviendo" donde estuvo último)
  function _dispEnEstacion(idEstacion) {
    return (cfgData.dispositivos || []).filter(d => {
      if (String(d.Estado).toUpperCase() !== 'ACTIVO') return false;
      return String(d.Ultima_Estacion || '') === String(idEstacion);
    });
  }

  // Devuelve solo dispositivos que NUNCA se han logueado en una estación
  // (recién aprobados o registrados a mano sin sesión todavía)
  function _dispMoviles() {
    return (cfgData.dispositivos || []).filter(d => {
      const estado = String(d.Estado).toUpperCase();
      if (estado === 'PENDIENTE_APROBACION') return false; // van en sección aparte
      if (estado === 'INACTIVO') return false;             // bloqueados no se muestran como móviles
      return !d.Ultima_Estacion; // solo los que nunca tuvieron estación
    });
  }

  // Detectar si el dispositivo se movió de estación entre renders
  function _dispSeMovio(d) {
    if (_dispRenderCount === 0) return false; // primer render, no animar
    const prev = _dispUltimaEstacionMap[d.ID_Dispositivo];
    const ahora = String(d.Ultima_Estacion || '');
    return prev !== undefined && prev !== ahora;
  }

  function _dispActualizarMapa() {
    let huboMovimientos = false;
    (cfgData.dispositivos || []).forEach(d => {
      const prev = _dispUltimaEstacionMap[d.ID_Dispositivo];
      const ahora = String(d.Ultima_Estacion || '');
      // Detectar movimiento real (entre 2 renders, ambas estaciones definidas)
      if (_dispRenderCount > 0 && prev !== undefined && prev !== '' && prev !== ahora && ahora) {
        const ico = _dispIcono(d.Nombre_Equipo);
        const nombre = d.Nombre_Equipo || 'Dispositivo';
        _dispFantasmas[d.ID_Dispositivo] = {
          desde: prev,
          hacia: ahora,
          ico,
          nombre,
          expira: Date.now() + 5000
        };
        // E: Toast notif del movimiento
        const estDest = (cfgData.estaciones || []).find(e => e.idEstacion === ahora);
        const nombreDest = estDest?.nombre || ahora;
        try { toast(`📍 ${nombre} se movió a ${nombreDest}`, 'ok'); } catch(_) {}
        huboMovimientos = true;
      }
      _dispUltimaEstacionMap[d.ID_Dispositivo] = ahora;
    });
    _dispRenderCount++;
    // Programar re-render para que los fantasmas desaparezcan a los 5s
    if (huboMovimientos) {
      if (_dispCleanupTimer) clearTimeout(_dispCleanupTimer);
      _dispCleanupTimer = setTimeout(() => {
        _dispCleanupTimer = null;
        if (S.cfgTab === 'infra') renderInfra();
      }, 5200);
    }
  }

  // Devuelve fantasmas vigentes que partieron de esta estación
  function _dispFantasmasDeEstacion(idEstacion) {
    const ahora = Date.now();
    return Object.entries(_dispFantasmas)
      .filter(([id, f]) => f.desde === idEstacion && f.expira > ahora)
      .map(([id, f]) => ({ id, ...f }));
  }

  // Cuenta dispositivos online (ACTIVO + actividad <5 min) en una estación
  function _dispOnlineEnEstacion(idEstacion) {
    return _dispEnEstacion(idEstacion).filter(d =>
      _dispActividad(d.Ultima_Conexion).minutos < 5
    ).length;
  }

  // Toggle heatmap
  function infraToggleHeatmap() {
    _infraHeatmapActivo = !_infraHeatmapActivo;
    renderInfra();
  }

  // Color del borde según densidad de dispositivos en estación (modo heatmap)
  function _heatmapColor(cantOnline) {
    if (cantOnline === 0) return { bg: 'transparent', border: '#1e293b', label: '' };
    if (cantOnline === 1) return { bg: 'rgba(14,165,233,0.10)',  border: '#0284c7', label: '🟦' };
    if (cantOnline === 2) return { bg: 'rgba(16,185,129,0.12)',  border: '#10b981', label: '🟩' };
    if (cantOnline === 3) return { bg: 'rgba(251,191,36,0.14)',  border: '#f59e0b', label: '🟨' };
    if (cantOnline <= 5)  return { bg: 'rgba(249,115,22,0.16)',  border: '#ea580c', label: '🟧' };
    return                       { bg: 'rgba(239,68,68,0.18)',   border: '#dc2626', label: '🟥' };
  }

  function _dispPendientes() {
    return (cfgData.dispositivos || []).filter(d =>
      String(d.Estado).toUpperCase() === 'PENDIENTE_APROBACION'
    );
  }

  // Render compacto de un chip de dispositivo (dentro de estación o lista global)
  function _renderDispositivoChip(d, opts) {
    opts = opts || {};
    const ico = _dispIcono(d.Nombre_Equipo);
    const act = _dispActividad(d.Ultima_Conexion);
    const idAttr = String(d.ID_Dispositivo).replace(/'/g, '&#39;');
    const isFresh = act.minutos < 5;
    const sesion = d.Ultima_Sesion ? ` · 👤 <span class="text-emerald-400 font-bold">${d.Ultima_Sesion}</span>` : '';
    const cls = opts.compact ? 'text-[10px] px-2 py-1.5' : 'text-[11px] px-3 py-2';
    const claseFresh = isFresh ? 'disp-chip-live' : '';
    const dotPulse = isFresh ? '<span class="disp-dot-pulse"></span>' : '';
    const pinBtn = '';
    const yaSoyBadge = '';
    return `<div class="disp-chip flex items-center gap-2 rounded-lg ${cls} ${claseFresh}"
      style="background:#0a1424;border:1px solid #1e293b;transition:all 0.2s;">
      <span class="text-base shrink-0 relative cursor-pointer" onclick="MOS.abrirModalDispositivo('${idAttr}')" title="Editar">${ico}${dotPulse}</span>
      <div class="flex-1 min-w-0 cursor-pointer" onclick="MOS.abrirModalDispositivo('${idAttr}')">
        <div class="font-medium text-slate-200 truncate">${d.Nombre_Equipo || '—'} ${yaSoyBadge}</div>
        <div class="text-[9px] truncate" style="color:${act.color};">
          ${act.dot} ${act.label}${sesion}
        </div>
      </div>
      ${pinBtn}
      <button onclick="event.stopPropagation();MOS.abrirEspiaDispositivo('${idAttr}')" class="shrink-0 w-7 h-7 rounded-full flex items-center justify-center hover:scale-110 transition-all" style="background:rgba(99,102,241,0.18);border:1px solid rgba(99,102,241,0.5);color:#a5b4fc;font-size:11px;" title="Espiar dispositivo (audio + GPS)">🕵️</button>
      <button onclick="event.stopPropagation();MOS.abrirModalDispositivo('${idAttr}')" class="text-[10px] text-slate-500 hover:text-white p-1" title="Editar">✏️</button>
    </div>`;
  }

  // Config CRUD
  function _estActualizarPreview() {
    const nom = ($('estNombre')?.value || '').trim();
    const tipo = $('estTipo')?.value || 'CAJA';
    const app = $('estApp')?.value || 'mosExpress';
    const idZona = $('estZona')?.value || '';
    const zonaName = idZona ? (cfgData.zonas.find(z => z.idZona === idZona)?.nombre || '—') : 'Sin zona';
    const tipoIcon = { CAJA: '🛒', ALMACEN: '🏭', ENVASADO: '🍶' }[tipo] || '📍';
    const appLbl = app === 'mosExpress' ? 'ME' : 'WH';
    const sub = $('modalEstSubtitle');
    if (sub) sub.textContent = nom ? `${tipo} · ${appLbl} · ${zonaName}` : 'Caja / almacén';
    const ico = $('estIconPreview');
    if (ico) ico.textContent = tipoIcon;
  }

  function abrirModalEstacion(id, presetIdZona) {
    ['Id','Nombre','Tipo','App','Pin','Desc'].forEach(f => {
      const el = $('est' + f); if (el && el.tagName !== 'SELECT') el.value = '';
    });
    // Poblar select de zonas dinámicamente
    const zonaSelect = $('estZona');
    if (zonaSelect) {
      zonaSelect.innerHTML = '<option value="">— Sin zona —</option>' +
        cfgData.zonas.filter(z => z.estado === '1' || z.estado === 1).map(z =>
          `<option value="${z.idZona}">${z.nombre}</option>`
        ).join('');
    }
    const estadoWrap = $('estEstadoWrap');
    const btnElim = $('estBtnEliminar');
    const tg = $('estEstadoToggle');
    if (id) {
      const e = cfgData.estaciones.find(x => x.idEstacion === id);
      if (!e) return;
      $('modalEstTitle').textContent = 'Editar Estación';
      $('estId').value     = e.idEstacion;
      $('estNombre').value = e.nombre || '';
      if (zonaSelect) zonaSelect.value = e.idZona || '';
      $('estTipo').value   = e.tipo || 'CAJA';
      $('estApp').value    = e.appOrigen || 'mosExpress';
      $('estDesc').value   = e.descripcion || '';
      if (tg) tg.checked = String(e.activo) === '1' || e.activo === 1 || e.activo === true;
      if (estadoWrap) estadoWrap.classList.remove('hidden');
      if (btnElim)    btnElim.classList.remove('hidden');
    } else {
      $('modalEstTitle').textContent = 'Nueva Estación';
      $('estId').value = '';
      $('estTipo').value = 'CAJA';
      $('estApp').value = 'mosExpress';
      if (tg) tg.checked = true;
      if (estadoWrap) estadoWrap.classList.add('hidden');
      if (btnElim)    btnElim.classList.add('hidden');
      // Preset de zona si se está creando desde dentro de una zona
      if (presetIdZona && zonaSelect) zonaSelect.value = presetIdZona;
    }
    _estActualizarPreview();
    openModal('modalEstacion');
  }

  async function guardarEstacion() {
    const idEdit = $('estId')?.value || undefined;
    const tg = $('estEstadoToggle');
    const params = {
      idEstacion:  idEdit,
      nombre:      ($('estNombre')?.value || '').trim(),
      idZona:      $('estZona')?.value || '',
      tipo:        $('estTipo')?.value || 'CAJA',
      appOrigen:   $('estApp')?.value || 'mosExpress',
      descripcion: $('estDesc')?.value || ''
    };
    if (idEdit) params.activo = (tg && tg.checked) ? '1' : '0';
    if (!params.nombre) { toast('Nombre requerido', 'error'); return; }
    if (!params.idEstacion) delete params.idEstacion;
    // OPTIMISTA
    const list = cfgData.estaciones;
    const backup = list.slice();
    if (idEdit) {
      const idx = list.findIndex(x => x.idEstacion === idEdit);
      if (idx >= 0) list[idx] = { ...list[idx], ...params };
    } else {
      list.push({ ...params, idEstacion: 'EST_TMP' + Date.now(), activo: '1', _tmp: true });
    }
    closeModal('modalEstacion');
    renderInfra();
    try {
      const res = await API.post(idEdit ? 'actualizarEstacion' : 'crearEstacion', params);
      if (!idEdit && res?.idEstacion) {
        const tmp = list.findIndex(x => x._tmp);
        if (tmp >= 0) { list[tmp].idEstacion = res.idEstacion; delete list[tmp]._tmp; }
      }
      toast('Estación guardada ✓', 'ok');
      renderInfra();
      // Auto-replicación: si es nueva y la zona ya tiene series, crearlas para esta estación
      if (!idEdit && res?.idEstacion && params.idZona) {
        await _replicarSeriesParaNuevaEstacion(res.idEstacion, params.idZona);
      }
    } catch(e) {
      cfgData.estaciones = backup;
      renderInfra();
      toast('Error: ' + e.message, 'error');
    }
  }

  // Si la zona ya tiene series configuradas, crear las filas correspondientes
  // para la nueva estación. Cada nueva fila empieza con correlativo=1.
  // El nombre de la serie se toma de la mayoría existente en la zona.
  async function _replicarSeriesParaNuevaEstacion(idEstacion, idZona) {
    if (!idEstacion || !idZona) return;
    const seriesZona = (cfgData.series || []).filter(s =>
      s.idZona === idZona && s.idEstacion !== idEstacion
    );
    if (!seriesZona.length) return; // zona sin series — no hay nada que replicar

    // Agrupar por tipoDocumento → escoger el nombre más frecuente
    const porTipo = {};
    seriesZona.forEach(s => {
      const k = s.tipoDocumento;
      if (!porTipo[k]) porTipo[k] = [];
      porTipo[k].push(s);
    });

    const nuevasFilas = [];
    Object.keys(porTipo).forEach(tipo => {
      const grupos = porTipo[tipo];
      const conteo = {};
      grupos.forEach(s => { conteo[s.serie] = (conteo[s.serie] || 0) + 1; });
      const nombreMasComun = Object.entries(conteo).sort((a, b) => b[1] - a[1])[0][0];
      // Verificar si ya existe (defensa contra duplicados)
      const yaExiste = (cfgData.series || []).some(s =>
        s.idEstacion === idEstacion && s.tipoDocumento === tipo
      );
      if (!yaExiste) {
        nuevasFilas.push({
          idEstacion,
          idZona,
          tipoDocumento: tipo,
          serie: nombreMasComun,
          correlativo: 1,
          activo: '1'
        });
      }
    });

    if (!nuevasFilas.length) return;

    // OPTIMISTA: agregar a cfgData.series con id temporal
    nuevasFilas.forEach(f => {
      cfgData.series.push({ ...f, idSerie: 'SER_TMP' + Date.now() + '_' + f.tipoDocumento, _tmp: true });
    });
    renderInfra();

    try {
      await Promise.all(nuevasFilas.map(f =>
        API.post('crearSerie', f).then(res => {
          if (res?.idSerie) {
            const tmp = cfgData.series.find(s => s._tmp && s.idEstacion === idEstacion && s.tipoDocumento === f.tipoDocumento);
            if (tmp) { tmp.idSerie = res.idSerie; delete tmp._tmp; }
          }
        })
      ));
      toast(`✓ Auto-replicadas ${nuevasFilas.length} serie${nuevasFilas.length === 1 ? '' : 's'} desde la zona`, 'ok');
      renderInfra();
    } catch(e) {
      console.error('[replicar series]', e);
      // Quitar las _tmp que no pudieron sincronizarse
      cfgData.series = cfgData.series.filter(s => !s._tmp);
      renderInfra();
      toast('La estación se creó pero falló la replicación de series', 'warn');
    }
  }

  async function eliminarEstacion() {
    const id = $('estId')?.value;
    if (!id) return;
    const e = cfgData.estaciones.find(x => x.idEstacion === id);
    if (!e) return;
    const numImp = cfgData.impresoras.filter(i => i.idEstacion === id).length;
    const msg = numImp > 0
      ? `¿Desactivar la estación "${e.nombre}"?\n\nTiene ${numImp} impresora${numImp === 1 ? '' : 's'} asociada${numImp === 1 ? '' : 's'}. Puedes reactivarla luego.`
      : `¿Desactivar la estación "${e.nombre}"?\n\nPodrás reactivarla cuando quieras.`;
    if (!confirm(msg)) return;
    closeModal('modalEstacion');
    const previo = e.activo;
    e.activo = '0';
    renderInfra();
    try {
      await API.post('actualizarEstacion', { idEstacion: id, activo: '0' });
      toast('Estación desactivada', 'ok');
    } catch(err) {
      e.activo = previo;
      renderInfra();
      toast('Error: ' + err.message, 'error');
    }
  }

